import{_ as a,o as e,c as i,ag as t}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"RustChat Admin Guide","description":"","frontmatter":{},"headers":[],"relativePath":"admin/installation.md","filePath":"admin/installation.md","lastUpdated":1775719799000}'),n={name:"admin/installation.md"};function r(o,s,l,d,p,h){return e(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="rustchat-admin-guide" tabindex="-1">RustChat Admin Guide <a class="header-anchor" href="#rustchat-admin-guide" aria-label="Permalink to &quot;RustChat Admin Guide&quot;">​</a></h1><p>This guide is intended for system administrators, DevOps engineers, and IT staff responsible for deploying, configuring, and maintaining RustChat.</p><hr><h2 id="_1-introduction" tabindex="-1">1. Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1. Introduction&quot;">​</a></h2><h3 id="admin-responsibilities" tabindex="-1">Admin Responsibilities <a class="header-anchor" href="#admin-responsibilities" aria-label="Permalink to &quot;Admin Responsibilities&quot;">​</a></h3><p>As a RustChat administrator, you are responsible for:</p><ul><li><strong>System Availability:</strong> Ensuring the backend, frontend, and database services are running smoothly.</li><li><strong>Security:</strong> Managing SSL/TLS certificates, firewall rules, and authentication settings.</li><li><strong>Scaling:</strong> Monitoring resource usage and scaling services to meet user demand.</li><li><strong>Data Integrity:</strong> Configuring regular backups for the PostgreSQL database and S3 file storage.</li><li><strong>User Management:</strong> Onboarding users, managing roles, and overseeing system-wide settings.</li></ul><h3 id="supported-environments" tabindex="-1">Supported Environments <a class="header-anchor" href="#supported-environments" aria-label="Permalink to &quot;Supported Environments&quot;">​</a></h3><p>RustChat is designed to be highly portable:</p><ul><li><strong>Bare Metal:</strong> High-performance direct deployment on Linux servers.</li><li><strong>Docker Compose:</strong> Ideal for small teams or development/staging environments.</li><li><strong>Kubernetes:</strong> Best for high availability and enterprise-scale deployments using Helm.</li></ul><hr><h2 id="_2-architecture-overview" tabindex="-1">2. Architecture Overview <a class="header-anchor" href="#_2-architecture-overview" aria-label="Permalink to &quot;2. Architecture Overview&quot;">​</a></h2><p>RustChat follows a modern, decoupled architecture designed for speed and horizontal scalability.</p><ul><li><strong>Rust Backend:</strong> A high-performance REST API built with Axum and Tokio. It handles business logic, database interactions, and secure authentication.</li><li><strong>SPA Frontend:</strong> A Vue 3 + Vite single-page application served via Nginx. It provides a responsive, desktop-like experience in the browser.</li><li><strong>WebSocket Hub:</strong> A real-time subsystem that manages persistent active connections for instant message delivery, typing indicators, and presence updates.</li><li><strong>PostgreSQL:</strong> The primary relational database for message history, user profiles, and channel metadata.</li><li><strong>Redis (Optional/Recommended):</strong> Used for caching frequently accessed data and providing pub/sub capabilities for real-time events across multiple backend instances.</li><li><strong>File Storage:</strong> Flexible storage for user-uploaded files. Supports Local File Systems and S3-compatible backends like MinIO, Ceph RGW, or AWS S3.</li><li><strong>Load Balancer:</strong> Required for TLS termination and routing WebSocket traffic with sticky sessions (if scaling multiple backend pods).</li></ul><hr><h2 id="_3-installation-deployment" tabindex="-1">3. Installation &amp; Deployment <a class="header-anchor" href="#_3-installation-deployment" aria-label="Permalink to &quot;3. Installation &amp; Deployment&quot;">​</a></h2><h3 id="quick-start-with-docker-compose" tabindex="-1">Quick Start with Docker Compose <a class="header-anchor" href="#quick-start-with-docker-compose" aria-label="Permalink to &quot;Quick Start with Docker Compose&quot;">​</a></h3><p>For a quick local or small-scale setup:</p><ol><li><strong>Clone the Repo:</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/rustchat/rustchat.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rustchat</span></span></code></pre></div></li><li><strong>Configure Environment:</strong> Copy <code>.env.example</code> to <code>.env</code> and adjust the variables.</li><li><strong>Launch Services:</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span></code></pre></div>This starts the backend, frontend, PostgreSQL, Redis, and MinIO.</li></ol><h3 id="deployment-targets" tabindex="-1">Deployment Targets <a class="header-anchor" href="#deployment-targets" aria-label="Permalink to &quot;Deployment Targets&quot;">​</a></h3><h4 id="kubernetes" tabindex="-1">Kubernetes <a class="header-anchor" href="#kubernetes" aria-label="Permalink to &quot;Kubernetes&quot;">​</a></h4><p>For enterprise production environments, deploy RustChat with your standard Kubernetes manifests and ingress stack.</p><ul><li><strong>TLS:</strong> Terminate TLS at ingress (for example with Cert-Manager managed certificates).</li><li><strong>Auto-Scaling:</strong> Configure HPA for backend and frontend workloads.</li><li><strong>Note:</strong> This repository does not currently ship an official <code>helm/</code> chart directory.</li></ul><h4 id="bare-metal-systemd" tabindex="-1">Bare Metal / Systemd <a class="header-anchor" href="#bare-metal-systemd" aria-label="Permalink to &quot;Bare Metal / Systemd&quot;">​</a></h4><ol><li>Compile the backend: <code>cargo build --release</code>.</li><li>Install the binary as a Systemd service.</li><li>Serve the frontend <code>dist</code> folder using Nginx.</li></ol><hr><h2 id="_4-configuration" tabindex="-1">4. Configuration <a class="header-anchor" href="#_4-configuration" aria-label="Permalink to &quot;4. Configuration&quot;">​</a></h2><p>RustChat is configured primarily via environment variables with the <code>RUSTCHAT_</code> prefix.</p><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>RUSTCHAT_DATABASE_URL</code></td><td>PostgreSQL connection string.</td></tr><tr><td><code>RUSTCHAT_REDIS_URL</code></td><td>Redis connection string.</td></tr><tr><td><code>RUSTCHAT_ENVIRONMENT</code></td><td>Runtime mode (<code>development</code> or <code>production</code>).</td></tr><tr><td><code>RUSTCHAT_CORS_ALLOWED_ORIGINS</code></td><td>Comma-separated browser origin allowlist for CORS.</td></tr><tr><td><code>RUSTCHAT_S3_ENDPOINT</code></td><td>URL for your S3-compatible service.</td></tr><tr><td><code>RUSTCHAT_S3_BUCKET</code></td><td>The bucket name for file storage.</td></tr><tr><td><code>RUSTCHAT_JWT_SECRET</code></td><td>Secret key for signing session tokens.</td></tr><tr><td><code>RUSTCHAT_ENCRYPTION_KEY</code></td><td>Key used to encrypt/decrypt stored sensitive config values (for example OAuth client secrets).</td></tr><tr><td><code>RUSTCHAT_SMTP_HOST</code></td><td>Host for outgoing email notifications.</td></tr></tbody></table><p>Production guidance:</p><ul><li>Set <code>RUSTCHAT_ENVIRONMENT=production</code>.</li><li>Set <code>RUSTCHAT_CORS_ALLOWED_ORIGINS</code> explicitly (no wildcards).</li><li>Use long random values for <code>RUSTCHAT_JWT_SECRET</code> and <code>RUSTCHAT_ENCRYPTION_KEY</code>.</li></ul><hr><h2 id="_5-reverse-proxy-setup" tabindex="-1">5. Reverse Proxy Setup <a class="header-anchor" href="#_5-reverse-proxy-setup" aria-label="Permalink to &quot;5. Reverse Proxy Setup&quot;">​</a></h2><p>We recommend using <strong>Nginx</strong>, <strong>Traefik</strong>, or <strong>Caddy</strong> for TLS termination and basic load balancing.</p><h3 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐     HTTPS      ┌─────────────────┐     HTTP       ┌─────────────────┐</span></span>
<span class="line"><span>│   Web Browser   │───────────────▶│  Reverse Proxy  │───────────────▶│  RustChat API   │</span></span>
<span class="line"><span>│                 │                │  (TLS Termination)               │   (Port 3000)   │</span></span>
<span class="line"><span>└─────────────────┘                └─────────────────┘                └─────────────────┘</span></span>
<span class="line"><span>       https://chat.example.com         proxy_pass http://rustchat:3000</span></span></code></pre></div><h3 id="cors-configuration-behind-proxy" tabindex="-1">CORS Configuration Behind Proxy <a class="header-anchor" href="#cors-configuration-behind-proxy" aria-label="Permalink to &quot;CORS Configuration Behind Proxy&quot;">​</a></h3><p>When running behind a reverse proxy, configure RustChat with the <strong>public HTTPS URLs</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># .env - Production behind reverse proxy</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">RUSTCHAT_ENVIRONMENT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">production</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">RUSTCHAT_SITE_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">https://chat.example.com</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">RUSTCHAT_CORS_ALLOWED_ORIGINS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">https://chat.example.com</span></span></code></pre></div><p><strong>Important:</strong> Even though internal communication uses HTTP, you must configure <code>https://</code> origins for CORS because:</p><ul><li>Browsers see only the public HTTPS URL</li><li>CORS validation happens against the <code>Origin</code> header sent by browsers</li><li>Production mode requires <code>https://</code> for security</li></ul><h3 id="nginx-example-config" tabindex="-1">Nginx Example Config <a class="header-anchor" href="#nginx-example-config" aria-label="Permalink to &quot;Nginx Example Config&quot;">​</a></h3><p>Crucially, ensure your proxy supports WebSockets:</p><div class="language-nginx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    listen </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">443</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ssl http2;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    server_name </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">chat.example.com;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    </span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ssl_certificate </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/path/to/cert.pem;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ssl_certificate_key </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/path/to/key.pem;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    </span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    location</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> / </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        proxy_pass </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http://rustchat_backend;  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Internal HTTP backend</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        proxy_http_version </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Upgrade $http_upgrade;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Connection </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;upgrade&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Host $host;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        </span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # Forward client IP for rate limiting</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">X-Forwarded-For $proxy_add_x_forwarded_for;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">X-Real-IP $remote_addr;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><hr><h2 id="_6-maintenance-backups" tabindex="-1">6. Maintenance &amp; Backups <a class="header-anchor" href="#_6-maintenance-backups" aria-label="Permalink to &quot;6. Maintenance &amp; Backups&quot;">​</a></h2><h3 id="database-backups" tabindex="-1">Database Backups <a class="header-anchor" href="#database-backups" aria-label="Permalink to &quot;Database Backups&quot;">​</a></h3><p>Schedule daily <code>pg_dump</code> tasks for the PostgreSQL service. Store these backups off-site.</p><h3 id="file-storage-backups" tabindex="-1">File Storage Backups <a class="header-anchor" href="#file-storage-backups" aria-label="Permalink to &quot;File Storage Backups&quot;">​</a></h3><p>If using MinIO or Ceph, leverage their built-in replication tools. For AWS S3, enable bucket versioning.</p><h3 id="logs-monitoring" tabindex="-1">Logs &amp; Monitoring <a class="header-anchor" href="#logs-monitoring" aria-label="Permalink to &quot;Logs &amp; Monitoring&quot;">​</a></h3><p>RustChat outputs structured JSON logs. We recommend piping these into ELK (Elasticsearch, Logstash, Kibana) or Prometheus/Grafana for monitoring system health.</p>`,52)])])}const k=a(n,[["render",r]]);export{g as __pageData,k as default};
